CREATE TABLE "PUBLIC"."USER_FAVORITES"(
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY(START WITH 1) NOT NULL,
    "USER_ID" BIGINT NOT NULL,
    "TRACK_ID" BIGINT NOT NULL,
    "CREATED_AT" TIMESTAMP WITH TIME ZONE NOT NULL
);
ALTER TABLE "PUBLIC"."USER_FAVORITES" ADD CONSTRAINT "PUBLIC"."PK_USER_FAVORITES" PRIMARY KEY("ID");
ALTER TABLE "PUBLIC"."USER_FAVORITES" ADD CONSTRAINT "PUBLIC"."UK_USER_TRACK" UNIQUE("USER_ID", "TRACK_ID");
ALTER TABLE "PUBLIC"."USER_FAVORITES" ADD CONSTRAINT "PUBLIC"."FK_FAV_USER" FOREIGN KEY("USER_ID") REFERENCES "PUBLIC"."USERS"("ID");
ALTER TABLE "PUBLIC"."USER_FAVORITES" ADD CONSTRAINT "PUBLIC"."FK_FAV_TRACK" FOREIGN KEY("TRACK_ID") REFERENCES "PUBLIC"."TRACKS"("ID");
CREATE INDEX "PUBLIC"."IDX_FAV_USER_CREATED" ON "PUBLIC"."USER_FAVORITES"("USER_ID", "CREATED_AT" DESC);
